for line in open('logs/structured-2026-05-21.json'):
    try: d=json.loads(line)
    except: continue
    # find any key resembling route/path/url
    def walk(o,pre=''):
        if isinstance(o,dict):
            for k,v in o.items():
                if k in ('path','route','url','endpoint','request_path') and isinstance(v,str):
                    paths[v]=paths.get(v,0)+1
                if k in ('status_code','status') and isinstance(v,int):
                    codes[v]=codes.get(v,0)+1
                walk(v,k)
        elif isinstance(o,list):
            for i in o: walk(i,pre)
    walk(d)
print('STATUS CODES:',codes)
