1	/**
2	 * Persistent timeline that records each completed onboarding stage as a
3	 * `CompletedStageAccordion`. Renders between `MessagesRegion` and the active
4	 * stage panel; each accordion appears as its stage is acked and stays for
5	 * the rest of the flow so the user can scroll up and re-open any prior step.
6	 *
7	 * Order matches the linear stage queue: writing style → todos → workflows →
8	 * platforms. The accordions are independent — the active stage is responsible
9	 * for rendering its own in-progress UI.
10	 */
11	
12	"use client";
13	
14	import { type Dispatch, useMemo } from "react";
15	import { FIELD_NAMES } from "../constants";
16	import { useConnectPlatform } from "../hooks/useConnectPlatform";
17	import type { UseOnboardingChatReturn } from "../hooks/useOnboardingChat";
18	import type { Action, OnboardingState } from "../state/types";
19	import { CompletedStageAccordion } from "./CompletedStageAccordion";
20	import { OnboardingPlatformConnect } from "./OnboardingPlatformConnect";
21	import { OnboardingTodoCards } from "./OnboardingTodoCards";
22	import { OnboardingWorkflowCards } from "./OnboardingWorkflowCards";
23	import { WritingStyleRevealCard } from "./reveal/WritingStyleRevealCard";
24	import { OnboardingChatStream } from "./stages/Chat";
25	
26	interface CompletedStagesTimelineProps {
27	  state: OnboardingState;
28	  dispatch: Dispatch<Action>;
29	  chat: UseOnboardingChatReturn;
30	}
31	
32	export function CompletedStagesTimeline({
33	  state,
34	  dispatch,
35	  chat,
36	}: CompletedStagesTimelineProps) {
37	  const { connect, skip } = useConnectPlatform(dispatch);
38	  const writingStyle = state.server?.writing_style;
39	  const todos = state.server?.onboarding_todos ?? [];
40	  const workflows = state.server?.suggested_workflows ?? [];
41	
42	  const showWriting = state.ackedWritingStyle && !!writingStyle?.style_summary;
43	  const showTodos = state.ackedTodos && todos.length > 0;
44	  const showWorkflows = state.workflowsConfirmed && workflows.length > 0;
45	  const showPlatforms = state.platformsConfirmed;
46	
47	  // OnboardingTodoCards types `source_email` as an object (not nullable). The
48	  // backend payload returns nullable, so normalise here before handing the list
49	  // off so we don't widen the card component's contract.
50	  const cardTodos = useMemo(
51	    () =>
52	      todos.map((t) => ({
53	        id: t.id,
54	        title: t.title,
55	        description: t.description ?? undefined,
56	        source_email: t.source_email ?? undefined,
57	      })),
58	    [todos],
59	  );
60	
61	  const executedTodoIds = useMemo(
62	    () =>
63	      state.todoExecutionTodo
64	        ? new Set([state.todoExecutionTodo.id])
65	        : new Set<string>(),
66	    [state.todoExecutionTodo],
67	  );
68	
69	  if (!showWriting && !showTodos && !showWorkflows && !showPlatforms) {
70	    return null;
71	  }
72	
73	  const executedTitle = state.todoExecutionTodo?.title;
74	
75	  return (
76	    <div className="mt-3 space-y-3">
77	      {showWriting && writingStyle?.style_summary && (
78	        <CompletedStageAccordion
79	          itemKey="writing-style"
80	          title="Writing style saved"
81	        >
82	          <WritingStyleRevealCard
83	            style_summary={writingStyle.style_summary}
84	            example={writingStyle.example ?? null}
85	            profession={state.responses[FIELD_NAMES.PROFESSION] ?? ""}
86	            embedded
87	          />
88	        </CompletedStageAccordion>
89	      )}
90	
91	      {showTodos && (
92	        <CompletedStageAccordion
93	          itemKey="todos"
94	          title={
95	            state.todoExecutionStarted && executedTitle
96	              ? `Ran "${executedTitle}"`
97	              : `Saved ${todos.length} ${todos.length === 1 ? "todo" : "todos"} for later`
98	          }
99	        >
100	          <div className="space-y-4">
101	            <OnboardingTodoCards
102	              todos={cardTodos}
103	              onExecuteTodo={() => {}}
104	              isExecuting={false}
105	              executingTodoId={null}
106	              completedTodoIds={executedTodoIds}
107	              readOnly
108	              embedded
109	            />
110	            {state.todoExecutionStarted && (
111	              <OnboardingChatStream chat={chat} hideRunNowUserMessage />
112	            )}
113	          </div>
114	        </CompletedStageAccordion>
115	      )}
116	
117	      {showWorkflows && (
118	        <CompletedStageAccordion
119	          itemKey="workflows"
120	          title={`${workflows.length} ${workflows.length === 1 ? "workflow" : "workflows"} added`}
121	        >
122	          <OnboardingWorkflowCards workflows={workflows} embedded />
123	        </CompletedStageAccordion>
124	      )}
125	
126	      {showPlatforms && (
127	        <CompletedStageAccordion
128	          itemKey="platforms"
129	          title={
130	            state.connectedPlatform
131	              ? `Connected ${state.connectedPlatform}`
132	              : "Skipped social connections"
133	          }
134	        >
135	          <OnboardingPlatformConnect
136	            onConnect={connect}
137	            onSkip={skip}
138	            onHoverPlatform={() => {}}
139	            connectedPlatform={state.connectedPlatform}
140	            hideSkip
141	            embedded
142	          />
143	        </CompletedStageAccordion>
144	      )}
145	    </div>
146	  );
147	}
148

